importScripts('./jsQR.js');

self.onmessage = function (event) {
    try {
        const imageData = event.data;
        const result = jsQR(
            imageData.data,
            imageData.width,
            imageData.height,
            { inversionAttempts: "dontInvert" }
        );

        self.postMessage(result ? result.data : null);
    } catch (err) {
        self.postMessage({ error: err.message });
    }
};
